// Simple LED Blink Circuit
// Red LED on pin 13 with 220Ω resistor

void setup() {
  // Configure pin 13 as an output
  pinMode(13, OUTPUT);
}

void loop() {
  // Turn the LED on
  digitalWrite(13, HIGH);
  delay(1000);  // Wait 1 second (1000 milliseconds)

  // Turn the LED off
  digitalWrite(13, LOW);
  delay(1000);  // Wait 1 second
}

