// ============================================
//   REACTION TIME GAME
//   LED lights up → Press button fast!
//   Shorter reaction time = Higher score
//   Components: LED (D13), Button (D2),
//               Buzzer (D8), LCD 16x2
// ============================================

#include <LiquidCrystal.h>

// --- Pin Definitions ---
const int LED_PIN    = 13;
const int BUTTON_PIN = 2;
const int BUZZER_PIN = 8;

// LCD: RS=12, EN=11, D4=7, D5=6, D6=5, D7=4
LiquidCrystal lcd(12, 11, 7, 6, 5, 4);

// --- Game State ---
int  totalScore    = 0;
int  round         = 1;
const int MAX_ROUNDS = 5;

// --- Timing ---
unsigned long ledOnTime   = 0;
const long    MAX_REACTION = 2000;  // 2 seconds to react

// --- Scoring ---
// Reaction time → score (out of 100)
int calcScore(unsigned long reactionMs) {
  if (reactionMs >= MAX_REACTION) return 0;
  return map(reactionMs, 0, MAX_REACTION, 100, 0);
}

// --- Sound Effects ---
void beepReady() {
  tone(BUZZER_PIN, 1000, 150);
  delay(200);
  tone(BUZZER_PIN, 1000, 150);
  delay(200);
}

void beepGo() {
  tone(BUZZER_PIN, 1800, 300);
}

void beepSuccess(int score) {
  if (score >= 80) {
    // Excellent!
    tone(BUZZER_PIN, 1500, 100); delay(120);
    tone(BUZZER_PIN, 2000, 100); delay(120);
    tone(BUZZER_PIN, 2500, 200);
  } else if (score >= 50) {
    // Good
    tone(BUZZER_PIN, 1500, 150); delay(200);
    tone(BUZZER_PIN, 1800, 200);
  } else {
    // Slow
    tone(BUZZER_PIN, 800, 400);
  }
}

void beepTooSlow() {
  tone(BUZZER_PIN, 400, 600);
}

void beepEarlyPress() {
  tone(BUZZER_PIN, 300, 500);
}

void beepGameOver() {
  tone(BUZZER_PIN, 600, 200); delay(250);
  tone(BUZZER_PIN, 400, 200); delay(250);
  tone(BUZZER_PIN, 200, 400);
}

// --- LCD Helpers ---
void lcdPrint(const char* line1, const char* line2 = "") {
  lcd.clear();
  lcd.setCursor(0, 0);
  lcd.print(line1);
  lcd.setCursor(0, 1);
  lcd.print(line2);
}

// ============================================
void setup() {
  pinMode(LED_PIN,    OUTPUT);
  pinMode(BUTTON_PIN, INPUT_PULLUP);
  pinMode(BUZZER_PIN, OUTPUT);

  lcd.begin(16, 2);

  // Welcome screen
  lcdPrint("  REACTION GAME ", "  Press to Start");
  beepReady();

  // Wait for first button press to start
  while (digitalRead(BUTTON_PIN) == LOW);   // debounce release
  delay(50);
  while (digitalRead(BUTTON_PIN) == HIGH);  // wait for press
  delay(50);
  while (digitalRead(BUTTON_PIN) == LOW);   // wait for release
  delay(300);
}

// ============================================
void loop() {
  if (round > MAX_ROUNDS) {
    // ---- GAME OVER SCREEN ----
    lcd.clear();
    lcd.setCursor(0, 0);
    lcd.print("  GAME OVER!    ");
    lcd.setCursor(0, 1);
    lcd.print("Total Score: ");
    lcd.print(totalScore);
    beepGameOver();
    delay(3000);

    // Grade
    float avg = totalScore / (float)MAX_ROUNDS;
    lcd.clear();
    lcd.setCursor(0, 0);
    if      (avg >= 85) lcd.print("  LEGENDARY!!  ");
    else if (avg >= 70) lcd.print("  EXCELLENT!   ");
    else if (avg >= 50) lcd.print("   GOOD JOB!   ");
    else                lcd.print("  KEEP TRYING  ");
    lcd.setCursor(0, 1);
    lcd.print("Avg: ");
    lcd.print((int)avg);
    lcd.print(" pts/round");
    delay(4000);

    // Reset game
    totalScore = 0;
    round      = 1;

    lcdPrint("  REACTION GAME ", "  Press to Start");
    beepReady();
    while (digitalRead(BUTTON_PIN) == LOW);
    delay(50);
    while (digitalRead(BUTTON_PIN) == HIGH);
    delay(50);
    while (digitalRead(BUTTON_PIN) == LOW);
    delay(300);
    return;
  }

  // ---- ROUND START ----
  lcd.clear();
  lcd.setCursor(0, 0);
  lcd.print("Round ");
  lcd.print(round);
  lcd.print("/");
  lcd.print(MAX_ROUNDS);
  lcd.setCursor(0, 1);
  lcd.print("Score: ");
  lcd.print(totalScore);
  delay(1500);

  // Countdown: GET READY
  lcdPrint("  GET READY...  ", "");
  delay(800);

  // Random wait before LED lights (1.5 – 4.5 seconds)
  long waitTime = random(1500, 4500);
  unsigned long waitStart = millis();

  // Check for early button press during wait
  bool earlyPress = false;
  while (millis() - waitStart < (unsigned long)waitTime) {
    if (digitalRead(BUTTON_PIN) == LOW) {
      earlyPress = true;
      break;
    }
  }

  if (earlyPress) {
    // ---- EARLY PRESS PENALTY ----
    digitalWrite(LED_PIN, LOW);
    lcdPrint(" TOO EARLY! -20 ", "  Wait for LED!");
    beepEarlyPress();
    totalScore = max(0, totalScore - 20);
    delay(2000);
    // Don't advance round — try again
    delay(500);
    return;
  }

  // ---- LIGHT THE LED ----
  digitalWrite(LED_PIN, HIGH);
  beepGo();
  ledOnTime = millis();

  lcdPrint("  >> PRESS IT <<", "");

  // Wait for button press or timeout
  bool pressed   = false;
  bool tooSlow   = false;

  while (true) {
    if (digitalRead(BUTTON_PIN) == LOW) {
      pressed = true;
      break;
    }
    if (millis() - ledOnTime >= MAX_REACTION) {
      tooSlow = true;
      break;
    }
  }

  unsigned long reactionTime = millis() - ledOnTime;
  digitalWrite(LED_PIN, LOW);

  if (tooSlow) {
    // ---- TOO SLOW ----
    lcdPrint(" TOO SLOW!  +0  ", "  2000ms+       ");
    beepTooSlow();
    delay(2000);
  } else {
    // ---- SCORED ----
    int roundScore = calcScore(reactionTime);
    totalScore += roundScore;

    lcd.clear();
    lcd.setCursor(0, 0);
    lcd.print("Time: ");
    lcd.print(reactionTime);
    lcd.print("ms");
    lcd.setCursor(0, 1);
    lcd.print("Score +");
    lcd.print(roundScore);
    lcd.print(" = ");
    lcd.print(totalScore);

    beepSuccess(roundScore);
    delay(2500);
  }

  round++;
  delay(500);
}

